        function refreshSelect2(whatFor) {
            $(`.select2-${whatFor}`).select2({
                ajax: {
                    url: whatFor == 'vendor' ? '{{ route('mas_rek_t_v2') }}' : (whatFor == 'gl' ?
                        '{{ route('mas_gl_t_v2') }}' : (whatFor == 'cashflow' ?
                            '{{ route('mas_cashflow') }}' : (whatFor == 'profitcenter' ?
                                '{{ route('mas_profitcenter') }}' : (whatFor == 'customer' ?
                                    '{{ route('master_customer') }}' : '')))),
                    dataType: 'json',
                    data: function (params) {
                        var query = {
                            q: params.term,
                            page: params.page || 1
                        }

                        return query;
                    },
                    processResults: function (data, params) {
                        var mappedData = data.result.map(function (item) {
                            if (whatFor == 'vendor') {
                                return {
                                    id: item.master_rekening_id,
                                    text: `${item.master_rekening_kode_sap} (${item.master_rekening_keterangan})`
                                };
                            } else if (whatFor == 'gl') {
                                return {
                                    id: `${item.master_gl_id}`,
                                    text: `${item.master_gl_kode} (${item.master_gl_keterangan})`,
                                };
                            } else if (whatFor == 'cashflow') {
                                return {
                                    id: `${item.master_cash_flow_id}`,
                                    text: `${item.master_cash_flow_key} - ${item.master_cash_flow_keterangan}`,
                                };
                            } else if (whatFor == 'profitcenter') {
                                return {
                                    id: `${item.master_profit_center_id}`,
                                    text: `${item.master_profit_center_kode} ${item.master_profit_unit}`,
                                }
                            } else if (whatFor == 'customer') {
                                return {
                                    id: `${item.master_customer_id}`,
                                    text: `${item.master_customer_kode_sap} (${item.master_customer_nama})`,
                                }
                            } else {
                                return {};
                            }
                        });

                        return {
                            results: mappedData,
                            pagination: {
                                more: data.incomplete_results
                            }
                        };
                    },
                    cache: true
                },
                placeholder: whatFor == 'vendor' ? '-- Pilih Kode Vendor --' : (whatFor == 'gl' ?
                    '-- Pilih Kode GL --' : (whatFor == 'cashflow' ? '-- Pilih Cashflow --' : (whatFor ==
                        'profitcenter' ? '-- Pilih Profit Center --' : ''))),
                width: '100%',
            });
        }
    </script>

