        function hapus_dokumen_pendukung_sppb(isi) {
            $("#dokumen_pendukung_sppb_" + isi).remove();

            // Cek apakah semua dokumen sudah dihapus
            if ($("[id^=dokumen_pendukung_sppb_]").length === 0) {
                $("#dokumen_pendukung_sppb").attr('required', true);
                $("#dokumen_pendukung_sppb").parent().css('border-color', 'red');
                console.log('Semua dokumen pendukung SPPB sudah terhapus, field menjadi wajib.');
            }
        }

