        $('#metode_pembayaran_sppb').change(function (event) {
            console.log('Selected value: ', $('#metode_pembayaran_sppb').val()); // Melihat nilai yang dipilih

            if ($('#jenis_spp').val() == 'karyawan') {
                $('#pilih_lampirkan_sppb_vendor').hide();

                switch ($('#metode_pembayaran_sppb').val()) {
                    case 'kas_negara':
                        $('#pilih_lampirkan_sppb').hide();
                        $('#nama_kas_input_1').show();
                        $('#alamat_kas_input_1').show();
                        break;
                    case 'kas':
                        $('#pilih_lampirkan_sppb').hide();
                        $('#nama_kas_input_1').hide();
                        $('#alamat_kas_input_1').hide();
                        $('#tidak_transfer').show();
                        $('#bank_sppb_karyawan').hide();
                        $('#nama_bank_sppb_karyawan').hide();
                        $('#rekening_bank_sppb_karyawan').hide();
                        $('#atas_nama_bank_sppb_karyawan').hide();
                        break;
                    default:
                        $('#pilih_lampirkan_sppb').show();
                        $('#nama_kas_input_1').hide();
                        $('#alamat_kas_input_1').hide();
                        $('#tidak_transfer').hide();
                }
                pilih_data_sppb_karyawan.call();
            } else {
                $('#pilih_lampirkan_sppb').hide();

                switch ($('#metode_pembayaran_sppb').val()) {
                    case 'kas_negara':
                        $('#pilih_lampirkan_sppb_vendor').hide();
                        $('#nama_kas_input_1').show();
                        $('#alamat_kas_input_1').show();
                        break;
                    case 'kas':
                        $('#pilih_lampirkan_sppb_vendor').hide();
                        $('#nama_kas_input_1').hide();
                        $('#alamat_kas_input_1').hide();
                        $('#tidak_transfer').show();
                        break;
                    default:
                        $('#pilih_lampirkan_sppb_vendor').show();
                        $('#nama_kas_input_1').hide();
                        $('#alamat_kas_input_1').hide();
                        $('#tidak_transfer').hide();
                }
                pilih_data_sppb_vendor.call();
            }
        });


