        function js_sppb(index) {
            //alert("aa");
            // console.log(index);
            var pilihan = $('#jenis_sap_sppb_' + index).val();
            console.log($('#jenis_sap_sppb_' + index), index);
            if (pilihan == 'vendor') {
                $('#sap_vendor_sppb_' + index).attr('class', "form-control select2-vendor slct_rekening unload");
                $('#sap_gl_sppb_' + index).attr('class', "form-control");
                $('#sap_customer_sppb_' + index).attr('class', "form-control");
                // document.getElementById("sap_vendor_sppb_" + index).className =
                //     "form-control selectpicker slct_rekening unload";
                // document.getElementById("sap_gl_sppb_" + index).className = "form-control selectpicker";
                // document.getElementById("sap_customer_sppb_" + index).className = "form-control selectpicker";
                var inputs = document.getElementsByClassName("validate_sppb");
                if (inputs) {
                    for (var i = 0; i < inputs.length; i++) {
                        inputs[i].addEventListener("change", validateInput);
                        inputs[i].addEventListener("keyup", validateInput);
                    }
                }
                $('#nomor_vendor_sppb_' + index).show();
                $('#nomor_gl_sppb_' + index).hide();
                $('#nomor_customer_sppb_' + index).hide();

                refreshSelect2(pilihan);

            } else if (pilihan == 'gl') {
                $('#sap_gl_sppb_' + index).attr('class', "form-control select2-gl slct_sppb");
                $('#sap_vendor_sppb_' + index).attr('class', "form-control");
                $('#sap_customer_sppb_' + index).attr('class', "form-control");
                // document.getElementById("sap_gl_sppb_" + index).className = "form-control selectpicker slct_sppb";
                // document.getElementById("sap_vendor_sppb_" + index).className = "form-control selectpicker";
                // document.getElementById("sap_customer_sppb_" + index).className = "form-control selectpicker";
                var inputs = document.getElementsByClassName("validate_sppb");
                if (inputs) {
                    for (var i = 0; i < inputs.length; i++) {
                        inputs[i].addEventListener("change", validateInput);
                        inputs[i].addEventListener("keyup", validateInput);
                    }
                }
                $('#nomor_vendor_sppb_' + index).hide();
                $('#nomor_gl_sppb_' + index).show();
                $('#nomor_customer_sppb_' + index).hide();

                refreshSelect2(pilihan);

                $.ajaxSetup({
                    headers: {
                        'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content')
                    }
                });

                var gl_id = $('#sap_gl_sppb_' + index).find(':selected').val();
                if (gl_id != undefined && gl_id != '') {
                    url = '{{ route('jumlah_budget', ['id' => 'gl_id']) }}';
                    url = url.replace('gl_id', gl_id);
                    $.ajax({
                        url: url,
                        type: 'GET',
                        success: function (response) {
                            var budeget = response.jumlah_budget;
                            // console.log(budeget, gl_id, $(this), index)
                            var reverse = budeget.toString().split('').reverse().join('');
                            ribuan = reverse.match(/\d{1,3}/g);
                            ribuan = ribuan.join('.').split('').reverse().join('');
                            $('.budget_gl_' + index).val('Rp. ' + ribuan);
                            $('.budget_gl_hide_' + index).val(budeget);
                            $.ajax({
                                type: 'POST',
                                url: "{{ route('realisasi') }}",
                                data: {
                                    gl_id: gl_id
                                },
                                success: function (data) {
                                    realisasi = parseInt(data.realisasisppn) + parseInt(data
                                        .realisasi);
                                    var reverse1 = realisasi.toString().split('').reverse().join(
                                        ''),
                                        ribuan1 = reverse1.match(/\d{1,3}/g);
                                    ribuan1 = ribuan1.join('.').split('').reverse().join('');
                                    $('.realisasi_' + index).val('Rp. ' + ribuan1);

                                    onproses = parseInt(data.onproses) + parseInt(data
                                        .onprosessppn);
                                    var reverse2 = onproses.toString().split('').reverse().join(''),
                                        ribuan2 = reverse2.match(/\d{1,3}/g);
                                    ribuan2 = ribuan2.join('.').split('').reverse().join('');
                                    $('.onproses_' + index).val('Rp. ' + ribuan2);

                                    sisa[index] = budeget - data.realisasi - data.onproses - data
                                        .realisasisppn - data
                                            .onprosessppn;
                                    var reverse3 = sisa[index].toString().split('').reverse().join(
                                        ''),
                                        ribuan3 = reverse3.match(/\d{1,3}/g);
                                    ribuan3 = ribuan3.join('.').split('').reverse().join('');
                                    $('.sisa_' + index).val('Rp. ' + ribuan3);
                                }
                            });
                        }
                    })
                }

                if (index_sppb_have_eventListener.indexOf(index) != -1) {
                    index_sppb_have_eventListener.push(index);
                    $('#sap_gl_sppb_' + index).on('change', function () {
                        var gl_id = $('#sap_gl_sppb_' + index).find(':selected').val();

                        var url = '{{ route('jumlah_budget', ['id' => 'gl_id']) }}';
                        url = url.replace('gl_id', gl_id);

                        $.ajax({
                            url: url,
                            type: 'GET',
                            success: function (response) {
                                //ways to retrieve selected option and text outside handler
                                var budeget = response.jumlah_budget;
                                // console.log(budeget, gl_id, $(this), index)
                                var reverse = budeget.toString().split('').reverse().join('');
                                ribuan = reverse.match(/\d{1,3}/g);
                                ribuan = ribuan.join('.').split('').reverse().join('');
                                $('.budget_gl_' + index).val('Rp. ' + ribuan);
                                $('.budget_gl_hide_' + index).val(budeget);
                                $.ajax({
                                    type: 'POST',
                                    url: "{{ route('realisasi') }}",
                                    data: {
                                        gl_id: gl_id
                                    },
                                    success: function (data) {
                                        realisasi = parseInt(data.realisasisppn) + parseInt(
                                            data.realisasi);
                                        var reverse1 = realisasi.toString().split('')
                                            .reverse().join(''),
                                            ribuan1 = reverse1.match(/\d{1,3}/g);
                                        ribuan1 = ribuan1.join('.').split('').reverse()
                                            .join('');
                                        $('.realisasi_' + index).val('Rp. ' + ribuan1);

                                        onproses = parseInt(data.onproses) + parseInt(data
                                            .onprosessppn);
                                        var reverse2 = onproses.toString().split('')
                                            .reverse().join(''),
                                            ribuan2 = reverse2.match(/\d{1,3}/g);
                                        ribuan2 = ribuan2.join('.').split('').reverse()
                                            .join('');
                                        $('.onproses_' + index).val('Rp. ' + ribuan2);

                                        sisa[index] = budeget - data.realisasi - data
                                            .onproses - data
                                                .realisasisppn - data.onprosessppn;
                                        var reverse3 = sisa[index].toString().split('')
                                            .reverse().join(''),
                                            ribuan3 = reverse3.match(/\d{1,3}/g);
                                        ribuan3 = ribuan3.join('.').split('').reverse()
                                            .join('');
                                        $('.sisa_' + index).val('Rp. ' + ribuan3);
                                    }
                                });
                            }
                        });
                    });
                }
                let dpp = document.getElementById('nominal_sppb_' + index + '_0')
                console.log(index)
                if (dpp.val != 0) {
                    bandingkan_dpp_sisa();
                }
            } else if (pilihan === 'customer') {
                $('#sap_customer_sppb_' + index).attr('class', "form-control select2-customer slct_sppb");
                $('#sap_vendor_sppb_' + index).attr('class', "form-control");
                $('#sap_gl_sppb_' + index).attr('form-control');
                // document.getElementById("sap_customer_sppb_" + index).className = "form-control selectpicker slct_sppb";
                // document.getElementById("sap_vendor_sppb_" + index).className = "form-control selectpicker";
                // document.getElementById("sap_gl_sppb_" + index).className = "form-control selectpicker";
                var inputs = document.getElementsByClassName("validate_sppb");
                if (inputs) {
                    for (var i = 0; i < inputs.length; i++) {
                        inputs[i].addEventListener("change", validateInput);
                        inputs[i].addEventListener("keyup", validateInput);
                    }
                }
                $('#nomor_vendor_sppb_' + index).hide();
                $('#nomor_gl_sppb_' + index).hide();
                $('#nomor_customer_sppb_' + index).show();

                refreshSelect2(pilihan);
            }

            // getDataRekening()
        }

